"use client";
import { IdCard, Lock, Mail, User, UserPlus } from "lucide-react";
import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";

export default function LoginPage() {
  const router = useRouter();
  const [fullName, setFullName] = useState("");
  const [email, setEmail] = useState("");
  const [universityId, setUniversityId] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [message, setMessage] = useState(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleRegister = async (e) => {
    e.preventDefault();
    setMessage(null);

    if (password !== confirmPassword) {
      setMessage({ type: "error", text: "Error: Passwords do not match." });
      return;
    }

    if (!fullName || !email || !universityId || !password) {
      setMessage({
        type: "error",
        text: "Error: Please fill in all required fields.",
      });
      return;
    }

    try {
      setIsLoading(true);

      // ✅ CALL YOUR REGISTER API HERE
      const res = await fetch("http://localhost:5000/user/register", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ fullName, email, password }),
      });
      //
      const data = await res.json();
      if (!res.ok) throw new Error(data.message);
      router.push(`/register/verify-otp?email=${email}`);
    } catch (err) {
      setMessage({ type: "error", text: err.message || "Registration failed" });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen px-20 flex">
      {/* Left Side */}
      <div className="w-1/2 bg-white flex flex-col justify-center items-start px-20">
        <div className="flex-row">
          <h1 className="text-2xl font-semibold mb-2 flex items-center">
            <UserPlus className="w-7 h-7 mr-2 text-black-600" />
            Register as a new user
          </h1>
        </div>

        <form
          onSubmit={handleRegister}
          className="w-full flex flex-col space-y-4"
        >
          {/* Full Name */}
          <div className="relative">
            <User className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="text"
              placeholder="Full Name"
              className="px-10 border w-100 h-10 border-gray-300 rounded-lg p-3 focus:outline-none focus:ring-2 focus:ring-blue-400"
              value={fullName}
              onChange={(e) => setFullName(e.target.value)}
            />
          </div>

          {/* Email */}
          <div className="relative">
            <Mail className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="text"
              placeholder="Email address"
              className="px-10 border w-100 h-10 border-gray-300 rounded-lg p-3 focus:outline-none focus:ring-2 focus:ring-blue-400"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>

          {/* University ID */}
          <div className="relative">
            <IdCard className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="text"
              placeholder="University ID"
              className="px-10 border w-100 h-10 border-gray-300 rounded-lg p-3 focus:outline-none focus:ring-2 focus:ring-blue-400"
              value={universityId}
              onChange={(e) => setUniversityId(e.target.value)}
            />
          </div>

          {/* Password */}
          <div className="relative">
            <Lock className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="password"
              placeholder="Password"
              className="px-10 border w-100 h-10 border-gray-300 rounded-lg p-3 focus:outline-none focus:ring-2 focus:ring-blue-400"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>

          {/* Confirm Password */}
          <div className="relative">
            <Lock className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="password"
              placeholder="Confirm Password"
              className="px-10 border w-100 h-10 border-gray-300 rounded-lg p-3 focus:outline-none focus:ring-2 focus:ring-blue-400"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
            />
          </div>

          {/* Button */}
          <button
            type="submit"
            className="bg-blue-500 max-w-40 h-10 text-white rounded-lg hover:bg-blue-600 transition"
          >
            {isLoading ? "Processing..." : "Sign Up"}
          </button>
        </form>

        {message && (
          <p
            className={`mt-3 text-sm ${
              message.type === "error" ? "text-red-500" : "text-green-600"
            }`}
          >
            {message.text}
          </p>
        )}

        <p className="text-sm text-gray-600 mt-3">
          Already have an account?
          <Link href="/login" className="text-blue-600 hover:underline ml-1">
            Sign in here
          </Link>
        </p>
      </div>

      {/* Right Side (Untouched) */}
      <div className="w-1/2 hover:scale-100 transition-transform duration-300 flex justify-center items-center">
        <img src="./register.jpg" alt="Login Hero" className="max-w-lg" />
      </div>
    </div>
  );
}
